			w.Close()
			os.Stdout = oldStdout

			var buf bytes.Buffer
			buf.ReadFrom(r)
			output := buf.String()
			if !strings.Contains(output, "not implemented yet") {
				t.Errorf("subcommand %q should print 'not implemented yet', got: %q", name, output)
			}
		})
	}
}

